const items = $input.all();
if (!items.length) return [];
const body = items[0].json.body || items[0].json;

const entry = body.entry;
if (!entry || !entry[0] || !entry[0].changes || !entry[0].changes[0]) {
  return [];
}

const value = entry[0].changes[0].value;
if (!value.messages || !value.messages[0]) {
  return [];
}

const phone = value.messages[0].from;
const message = value.messages[0];

return [{ json: { phone, message } }];

const items = $input.all();
if (!items.length) return [];
const data = items[0].json;

// Parse session from Redis (stored as JSON string) or create new
let session;
try {
  session = data.value ? JSON.parse(data.value) : { step: 1, cart: [], createdAt: new Date().toISOString() };
} catch(e) {
  session = { step: 1, cart: [], createdAt: new Date().toISOString() };
}

const parseData = $('Parse Incoming Message').first().json;
const phone = parseData.phone;
const message = parseData.message;
const incoming = message;
let { step, cart } = session;
let response;

// GREETING (step 1 or unrecognized)
if (step === 1 || !step) {
  response = {
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: '🍕 ¡Bienvenido a D\'Firu Pizza! ¿Qué deseas ordenar hoy?' },
      action: {
        buttons: [
          { type: 'reply', reply: { id: 'menu', title: 'Ver Menú' } },
          { type: 'reply', reply: { id: 'orders', title: 'Mis Pedidos' } },
          { type: 'reply', reply: { id: 'address', title: 'Cambiar Dirección' } }
        ]
      }
    }
  };
  step = 2;
}

// WAITING FOR MAIN MENU SELECTION
else if (step === 2) {
  const buttonId = incoming.interactive?.button_reply?.id;
  if (buttonId === 'menu') {
    response = {
      type: 'interactive',
      interactive: {
        type: 'list',
        header: { type: 'text', text: 'Nuestra Carta' },
        body: { text: 'Selecciona una categoría para ver los productos.' },
        action: {
          button: 'Ver Categorías',
          sections: [
            {
              title: 'Principales',
              rows: [
                { id: 'cat_pizza', title: 'Pizzas', description: 'Tradicionales y Especiales' },
                { id: 'cat_hamb', title: 'Hamburguesas', description: 'Res, Picosita, Doble' },
                { id: 'cat_chuzo', title: 'Chuzos', description: 'Mixtos, Pollo/Tocineta' },
                { id: 'cat_calzone', title: 'Calzones', description: 'Pizza cerrada' }
              ]
            },
            {
              title: 'Otros',
              rows: [
                { id: 'cat_pburg', title: 'Pizza Burguer', description: 'Original, D\'Firu, Paisa' },
                { id: 'cat_bebi', title: 'Bebidas', description: 'Jugos y Gaseosas' }
              ]
            }
          ]
        }
      }
    };
    step = 3;
  } else {
    response = { type: 'text', text: { body: 'Por favor selecciona una opción del menú 👆' } };
  }
}

// WAITING FOR CATEGORY SELECTION
else if (step === 3) {
  const catId = incoming.interactive?.list_reply?.id;
  if (catId === 'cat_pizza') {
    response = {
      type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: 'Selecciona el tamaño de tu Pizza' },
        action: {
          button: 'Ver Tamaños',
          sections: [{
            title: 'Tamaños',
            rows: [
              { id: 'prod_piz_peq', title: 'Pequeña', description: '$16.000' },
              { id: 'prod_piz_med', title: 'Mediana', description: '$30.000' },
              { id: 'prod_piz_gde', title: 'Grande', description: '$43.000' }
            ]
          }]
        }
      }
    };
    step = 4;
  } else if (catId === 'cat_hamb') {
    response = {
      type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: 'Selecciona tu Hamburguesa' },
        action: {
          button: 'Ver Hamburguesas',
          sections: [{
            title: 'Hamburguesas',
            rows: [
              { id: 'prod_hamb_res', title: 'Hamburguesa Res', description: '$18.000' },
              { id: 'prod_hamb_pic', title: 'Hamburguesa Picosita', description: '$20.000' },
              { id: 'prod_hamb_dob', title: 'Hamburguesa Doble', description: '$25.000' }
            ]
          }]
        }
      }
    };
    step = 4;
  } else if (catId === 'cat_bebi') {
    response = {
      type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: 'Selecciona tu Bebida' },
        action: {
          button: 'Ver Bebidas',
          sections: [{
            title: 'Bebidas',
            rows: [
              { id: 'prod_jugo', title: 'Jugo Natural', description: '$5.000' },
              { id: 'prod_gaseo', title: 'Gaseosa', description: '$3.000' }
            ]
          }]
        }
      }
    };
    step = 4;
  } else {
    response = { type: 'text', text: { body: 'Por favor selecciona una categoría de la lista 👆' } };
  }
}

// PRODUCT SELECTED → ADD TO CART
else if (step === 4) {
  const productId = incoming.interactive?.list_reply?.id;
  const productTitles = {
    'prod_piz_peq': { name: 'Pizza Pequeña', price: 16000 },
    'prod_piz_med': { name: 'Pizza Mediana', price: 30000 },
    'prod_piz_gde': { name: 'Pizza Grande', price: 43000 },
    'prod_hamb_res': { name: 'Hamburguesa Res', price: 18000 },
    'prod_hamb_pic': { name: 'Hamburguesa Picosita', price: 20000 },
    'prod_hamb_dob': { name: 'Hamburguesa Doble', price: 25000 },
    'prod_jugo': { name: 'Jugo Natural', price: 5000 },
    'prod_gaseo': { name: 'Gaseosa', price: 3000 }
  };

  const product = productTitles[productId];
  if (product) {
    cart.push(product);
    const total = cart.reduce((sum, p) => sum + p.price, 0);
    const cartSummary = cart.map((p, i) => `${i+1}. ${p.name} - $${p.price.toLocaleString()}`).join('\n');

    response = {
      type: 'interactive',
      interactive: {
        type: 'button',
        body: { text: `✅ *${product.name}* agregado al carrito!\n\n🛒 *Tu pedido:*\n${cartSummary}\n\n💰 *Total: $${total.toLocaleString()}*\n\n¿Qué deseas hacer?` },
        action: {
          buttons: [
            { type: 'reply', reply: { id: 'add_more', title: 'Agregar más' } },
            { type: 'reply', reply: { id: 'confirm_order', title: 'Confirmar pedido' } }
          ]
        }
      }
    };
    step = 5;
  } else {
    response = { type: 'text', text: { body: 'Por favor selecciona un producto de la lista 👆' } };
  }
}

// CONFIRM OR ADD MORE
else if (step === 5) {
  const buttonId = incoming.interactive?.button_reply?.id;
  if (buttonId === 'add_more') {
    response = {
      type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: 'Selecciona una categoría para agregar más productos' },
        action: {
          button: 'Ver Categorías',
          sections: [
            {
              title: 'Principales',
              rows: [
                { id: 'cat_pizza', title: 'Pizzas', description: 'Tradicionales y Especiales' },
                { id: 'cat_hamb', title: 'Hamburguesas', description: 'Res, Picosita, Doble' },
                { id: 'cat_chuzo', title: 'Chuzos', description: 'Mixtos, Pollo/Tocineta' },
                { id: 'cat_calzone', title: 'Calzones', description: 'Pizza cerrada' }
              ]
            },
            {
              title: 'Otros',
              rows: [
                { id: 'cat_pburg', title: 'Pizza Burguer', description: 'Original, D\'Firu, Paisa' },
                { id: 'cat_bebi', title: 'Bebidas', description: 'Jugos y Gaseosas' }
              ]
            }
          ]
        }
      }
    };
    step = 3;
  } else if (buttonId === 'confirm_order') {
    const total = cart.reduce((sum, p) => sum + p.price, 0);
    const cartSummary = cart.map((p, i) => `${i+1}. ${p.name} - $${p.price.toLocaleString()}`).join('\n');
    response = {
      type: 'interactive',
      interactive: {
        type: 'button',
        body: { text: `🎉 *Confirmar Pedido*\n\n${cartSummary}\n\n💰 *Total: $${total.toLocaleString()}*\n\n¿Cómo lo recibes?` },
        action: {
          buttons: [
            { type: 'reply', reply: { id: 'delivery', title: 'Domicilio' } },
            { type: 'reply', reply: { id: 'pickup', title: 'Para llevar' } }
          ]
        }
      }
    };
    step = 6;
  } else {
    response = { type: 'text', text: { body: 'Por favor usa los botones 👆' } };
  }
}

// DELIVERY TYPE
else if (step === 6) {
  const buttonId = incoming.interactive?.button_reply?.id;
  const total = cart.reduce((sum, p) => sum + p.price, 0);
  const tipo = buttonId === 'delivery' ? 'Domicilio 🛵' : 'Para llevar 🏃';
  cart = []; // reset cart after order
  step = 1;
  response = { type: 'text', text: { body: `✅ *¡Pedido recibido!*\n\nTipo: ${tipo}\nTotal: $${total.toLocaleString()}\n\n¡Gracias por tu pedido en D'Firu Pizza! Te avisamos cuando esté listo. 🍕` } };
}

else {
  step = 1;
  cart = [];
  response = { type: 'text', text: { body: 'Lo siento, algo salió mal. Escribe *hola* para empezar de nuevo.' } };
}

const metaPayload = {
  messaging_product: 'whatsapp',
  to: phone,
  type: response.type,
  ...response
};

return [{ json: { phone, response, step, cart, metaPayload } }];

const body = $input.first().json.body ?? $input.first().json;
const entry = body?.entry;
if (!entry?.[0]?.changes?.[0]) return [];
const value = entry[0].changes[0].value;
if (!value?.messages?.[0]) return [];
const msg = value.messages[0];
const phone = msg.from;
const msgType = msg.type;
let msgBody = null;
let buttonId = null;
let listId = null;
if (msgType === 'text') {
  msgBody = msg.text?.body || '';
} else if (msgType === 'interactive') {
  const iType = msg.interactive?.type;
  if (iType === 'button_reply') {
    buttonId = msg.interactive.button_reply?.id || null;
  } else if (iType === 'list_reply') {
    listId = msg.interactive.list_reply?.id || null;
  }
}
return [{ json: { phone, msgType, body: msgBody, buttonId, listId } }];

const parseData = $('Parse WA Payload').first().json;
const redisData = $('Redis Get Session').first().json;
const productsRaw = $('Get Products').first().json;
const saboresRaw = $('Get Sabores').first().json;

const products = Array.isArray(productsRaw) ? productsRaw : [];
const sabores = Array.isArray(saboresRaw) ? saboresRaw : [];

const phone = parseData.phone;
const msgType = parseData.msgType;
const msgBody = parseData.body;
const buttonId = parseData.buttonId;
const listId = parseData.listId;

let session;
try {
  session = redisData.value ? JSON.parse(redisData.value) : null;
} catch(e) {
  session = null;
}

if (!session || !session.step) {
  session = {
    step: 'await_tipo',
    tipoPedido: null,
    nombreCliente: null,
    telefonoCliente: phone,
    direccionCliente: null,
    metodoPago: null,
    observaciones: null,
    cart: [],
    cur: {}
  };
}

function fmt(n) { return '$' + Number(n).toLocaleString('es-CO'); }

function cartSummary(cart) {
  if (!cart.length) return 'El carrito esta vacio.';
  return cart.map((item, i) => {
    let line = `${i+1}. ${item.productoNombre} ${item.varianteNombre || ''} x${item.cantidad}`;
    if (item.sabor1) line += ` [${[item.sabor1, item.sabor2, item.sabor3].filter(Boolean).join('/')}]`;
    line += ` = ${fmt(item.subtotal)}`;
    return line;
  }).join('\n');
}

function cartTotal(cart) {
  return cart.reduce((s, i) => s + (Number(i.subtotal) || 0), 0);
}

function btnMsg(body, buttons, header) {
  const msg = {
    messaging_product: 'whatsapp',
    to: phone,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: String(body).substring(0, 1024) },
      action: { buttons }
    }
  };
  if (header) msg.interactive.header = { type: 'text', text: String(header).substring(0, 60) };
  return msg;
}

function listMsg(body, sections, buttonText, header) {
  const msg = {
    messaging_product: 'whatsapp',
    to: phone,
    type: 'interactive',
    interactive: {
      type: 'list',
      body: { text: String(body).substring(0, 1024) },
      action: {
        button: String(buttonText || 'Ver opciones').substring(0, 20),
        sections
      }
    }
  };
  if (header) msg.interactive.header = { type: 'text', text: String(header).substring(0, 60) };
  return msg;
}

function textMsg(text) {
  return {
    messaging_product: 'whatsapp',
    to: phone,
    type: 'text',
    text: { body: String(text).substring(0, 4096) }
  };
}

function activeVariants(product) {
  return (product.variantes || []).filter(v => v.activo !== false);
}

function buildProductListMsg() {
  const pizzas = products.filter(p => p.activo !== false && p.productoNombre.toLowerCase().includes('pizza'));
  const others = products.filter(p => p.activo !== false && !p.productoNombre.toLowerCase().includes('pizza'));
  const sections = [];
  if (pizzas.length) {
    sections.push({
      title: 'Pizzas',
      rows: pizzas.slice(0, 10).map(p => ({
        id: `prod_${p.productoId}`,
        title: p.productoNombre.substring(0, 24),
        description: activeVariants(p).map(v => `${v.nombre} ${fmt(v.precio)}`).join(' | ').substring(0, 72)
      }))
    });
  }
  if (others.length) {
    sections.push({
      title: 'Otros Productos',
      rows: others.slice(0, 10).map(p => ({
        id: `prod_${p.productoId}`,
        title: p.productoNombre.substring(0, 24),
        description: activeVariants(p).map(v => `${v.nombre} ${fmt(v.precio)}`).join(' | ').substring(0, 72)
      }))
    });
  }
  if (!sections.length) {
    sections.push({ title: 'Menu', rows: [{ id: 'no_prod', title: 'Sin productos', description: 'Contactenos directamente' }] });
  }
  return listMsg('Selecciona un producto:', sections, 'Ver Menu', "Menu D'Firu");
}

function buildSaboresListMsg(label) {
  const tradicionales = sabores.filter(s => s.activo !== false && s.tipo === 'tradicional');
  const especiales = sabores.filter(s => s.activo !== false && s.tipo !== 'tradicional');
  const toRow = s => ({
    id: `sab_${s.nombre.replace(/\s+/g, '_')}`,
    title: s.nombre.substring(0, 24),
    description: s.tipo !== 'tradicional' ? `Especial +${fmt(s.recargoGrande || 0)}` : 'Sabor clasico'
  });
  const sections = [];
  if (tradicionales.length) sections.push({ title: 'Sabores Clasicos', rows: tradicionales.slice(0, 10).map(toRow) });
  if (especiales.length) sections.push({ title: 'Sabores Especiales', rows: especiales.slice(0, 10).map(toRow) });
  if (!sections.length) sections.push({ title: 'Sabores', rows: [{ id: 'sab_Clasica', title: 'Clasica', description: 'Sabor de la casa' }] });
  return listMsg(label || 'Elige un sabor:', sections, 'Ver Sabores', 'Sabores Pizza');
}

let waPayload = null;
let needsOrderCreation = false;
let orderData = null;
let updatedSession = JSON.parse(JSON.stringify(session));

const step = session.step || 'await_tipo';
const cur = session.cur || {};

if (step === 'await_tipo') {
  waPayload = btnMsg(
    "Bienvenido a *D'Firu Pizza*!\n\nComo deseas tu pedido?",
    [
      { type: 'reply', reply: { id: 'tipo_mesa', title: 'En Mesa' } },
      { type: 'reply', reply: { id: 'tipo_llevar', title: 'Para Llevar' } },
      { type: 'reply', reply: { id: 'tipo_domicilio', title: 'Domicilio' } }
    ],
    "D'Firu Pizza"
  );
  updatedSession.step = 'await_tipo_select';
}

else if (step === 'await_tipo_select') {
  if (buttonId === 'tipo_mesa') {
    updatedSession.tipoPedido = 'mesa';
    updatedSession.step = 'await_product';
    waPayload = buildProductListMsg();
  } else if (buttonId === 'tipo_llevar') {
    updatedSession.tipoPedido = 'llevar';
    updatedSession.step = 'await_nombre';
    waPayload = textMsg('Escribe tu *nombre* para identificar tu pedido:');
  } else if (buttonId === 'tipo_domicilio') {
    updatedSession.tipoPedido = 'domicilio';
    updatedSession.step = 'await_nombre';
    waPayload = textMsg('Escribe tu *nombre completo*:');
  } else {
    waPayload = btnMsg(
      'Selecciona como deseas tu pedido:',
      [
        { type: 'reply', reply: { id: 'tipo_mesa', title: 'En Mesa' } },
        { type: 'reply', reply: { id: 'tipo_llevar', title: 'Para Llevar' } },
        { type: 'reply', reply: { id: 'tipo_domicilio', title: 'Domicilio' } }
      ]
    );
  }
}

else if (step === 'await_nombre') {
  if (msgType === 'text' && msgBody && msgBody.trim().length >= 2) {
    updatedSession.nombreCliente = msgBody.trim();
    if (session.tipoPedido === 'domicilio') {
      updatedSession.step = 'await_direccion';
      waPayload = textMsg('Escribe la *direccion de entrega*:');
    } else {
      updatedSession.step = 'await_product';
      waPayload = buildProductListMsg();
    }
  } else {
    waPayload = textMsg('Escribe tu nombre (minimo 2 caracteres):');
  }
}

else if (step === 'await_direccion') {
  if (msgType === 'text' && msgBody && msgBody.trim().length >= 5) {
    updatedSession.direccionCliente = msgBody.trim();
    updatedSession.step = 'await_product';
    waPayload = buildProductListMsg();
  } else {
    waPayload = textMsg('Escribe la *direccion completa* (minimo 5 caracteres):');
  }
}

else if (step === 'await_product') {
  if (listId && listId.startsWith('prod_')) {
    const prodId = parseInt(listId.replace('prod_', ''), 10);
    const product = products.find(p => p.productoId === prodId);
    if (product) {
      const isPizza = product.productoNombre.toLowerCase().includes('pizza');
      const variants = activeVariants(product);
      updatedSession.cur = {
        productoId: product.productoId,
        productoNombre: product.productoNombre,
        tipo: isPizza ? 'Pizza' : product.productoNombre,
        isPizza,
        varianteId: null, varianteNombre: null, variantePrecio: 0,
        sabor1: null, sabor2: null, sabor3: null, cantidad: 1
      };
      if (variants.length === 0) {
        waPayload = textMsg(`Lo sentimos, ${product.productoNombre} no esta disponible.`);
      } else if (variants.length === 1) {
        updatedSession.cur.varianteId = variants[0].varianteId;
        updatedSession.cur.varianteNombre = variants[0].nombre;
        updatedSession.cur.variantePrecio = Number(variants[0].precio) || 0;
        if (isPizza) {
          updatedSession.step = 'await_sabor1';
